FUNCTION PhongReflection(point, normal, lightPos, viewPos, material, lightColor)
 // Initialize result color
 ambientColor = material.ambient * lightColor

 // Calculate light direction (pointing from surface to light)
 lightDir = Normalize(lightPos - point)

 // DIFFUSE COMPONENT
 // Calculate angle between normal and light direction (dot product)
 diff = DotProduct(normal, lightDir)
 IF diff < 0 THEN diff = 0 // Light behind surface
 diffuseColor = material.diffuse * lightColor * diff

 // SPECULAR COMPONENT
 // Calculate view direction (pointing from surface to camera)
 viewDir = Normalize(viewPos - point)

 // Calculate reflection direction (reflect light off surface)
 reflectDir = Reflect(-lightDir, normal)

 // Calculate specular intensity using view angle
 spec = DotProduct(viewDir, reflectDir)
 IF spec < 0 THEN spec = 0

 // Apply shininess factor (higher = smaller highlight)
 spec = spec ^ material.shininess
 specularColor = material.specular * lightColor * spec

 // Combine all components
 finalColor = ambientColor + diffuseColor + specularColor

 RETURN finalColor
END FUNCTION

FUNCTION CalculateAttenuation(lightPos, surfacePos, constant, linear, quadratic)
 // Calculate distance from light to surface
 distance = Distance(lightPos, surfacePos)

 // ATTENUATION FORMULA: 1 / (c + l*d + q*d²)
 // where:
 // c = constant attenuation (maintains minimum intensity)
 // l = linear attenuation (gradual falloff)
 // q = quadratic attenuation (realistic physics-based)

 attenuationFactor = 1.0 / (constant + (linear * distance) + (quadratic * distance * distance))

 // Clamp to prevent division by zero or extreme values
 IF attenuationFactor > 1.0 THEN attenuationFactor = 1.0
 IF attenuationFactor < 0.0 THEN attenuationFactor = 0.0

 RETURN attenuationFactor
END FUNCTION

FUNCTION ApplyLightWithAttenuation(surfacePoint, normal, light, material)
 // Get base light contribution using Phong model
 baseColor = PhongReflection(surfacePoint, normal, light.position, 
 material.ambient, material.diffuse, 
 material.specular, material.shininess)

 // Calculate distance-based attenuation
 attenuation = CalculateAttenuation(
 light.position,
 surfacePoint,
 light.constant, // Typical value: 1.0
 light.linear, // Typical value: 0.09
 light.quadratic // Typical value: 0.032
 )

 // Apply attenuation to final color
 finalColor = baseColor * attenuation

 RETURN finalColor
END FUNCTION
